import { useState } from "react";
import {
  Eye, EyeOff, Mail, Lock, ArrowRight, CheckCircle,
  AlertCircle, RefreshCw, Shield, ChevronRight,
  Building2, User, Phone, Globe, Check, X, Info
} from "lucide-react";

const LOGO_B64 = "";
const LOGO_SRC = `data:image/png;base64,${LOGO_B64}`;

const checkStrength = (pw) => {
  const checks = {
    length: pw.length >= 8,
    upper: /[A-Z]/.test(pw),
    lower: /[a-z]/.test(pw),
    number: /[0-9]/.test(pw),
    special: /[^A-Za-z0-9]/.test(pw),
  };
  const score = Object.values(checks).filter(Boolean).length;
  return {
    checks, score,
    label: ["","Muy débil","Débil","Regular","Fuerte","Muy fuerte"][score],
    color: ["","#EF4444","#F97316","#EAB308","#22C55E","#10B981"][score]
  };
};

const C = {
  bg: "#070E1C", surface: "#0B1527", card: "#0F1D35", elevated: "#132240",
  border: "rgba(6,182,212,0.12)", borderFocus: "rgba(6,182,212,0.5)",
  primary: "#06B6D4", secondary: "#8B5CF6",
  success: "#10B981", danger: "#EF4444", warning: "#F59E0B",
  text: "#F1F5F9", textSec: "#94A3B8", textMuted: "#3D5070",
  gradPrimary: "linear-gradient(135deg,#06B6D4,#8B5CF6)",
};

function Input({ label, type="text", value, onChange, placeholder, icon:I, rightEl, error, hint }) {
  const [focused, setFocused] = useState(false);
  return (
    <div style={{marginBottom:16}}>
      {label && <div style={{fontSize:11,fontWeight:700,color:C.textMuted,textTransform:"uppercase",letterSpacing:".07em",marginBottom:6}}>{label}</div>}
      <div style={{position:"relative"}}>
        {I && <I size={15} style={{position:"absolute",left:14,top:"50%",transform:"translateY(-50%)",color:focused?C.primary:C.textMuted,transition:"color .2s",pointerEvents:"none"}}/>}
        <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
          onFocus={()=>setFocused(true)} onBlur={()=>setFocused(false)}
          style={{width:"100%",background:C.elevated,border:`1.5px solid ${error?C.danger:focused?C.borderFocus:C.border}`,
            borderRadius:12,padding:`12px ${rightEl?"48px":"14px"} 12px ${I?"42px":"14px"}`,
            color:C.text,fontSize:14,outline:"none",fontFamily:"inherit",transition:"border .2s, box-shadow .2s",
            boxSizing:"border-box",boxShadow:focused?`0 0 0 3px ${error?C.danger:C.primary}18`:"none"}}/>
        {rightEl && <div style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)"}}>{rightEl}</div>}
      </div>
      {error && <div style={{fontSize:11,color:C.danger,marginTop:5,display:"flex",alignItems:"center",gap:4}}><AlertCircle size={11}/>{error}</div>}
      {hint && !error && <div style={{fontSize:11,color:C.textMuted,marginTop:5}}>{hint}</div>}
    </div>
  );
}

function StrengthBar({password}) {
  if(!password) return null;
  const {checks,score,label,color} = checkStrength(password);
  return (
    <div style={{marginTop:-8,marginBottom:16}}>
      <div style={{display:"flex",gap:4,marginBottom:6}}>
        {[1,2,3,4,5].map(i=>(
          <div key={i} style={{flex:1,height:3,borderRadius:2,background:i<=score?color:C.border,transition:"background .3s"}}/>
        ))}
      </div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:11,color:color,fontWeight:600}}>{label}</span>
        <div style={{display:"flex",gap:8}}>
          {[["8+ chars",checks.length],["Mayúscula",checks.upper],["Número",checks.number],["Símbolo",checks.special]].map(([l,ok])=>(
            <span key={l} style={{fontSize:10,color:ok?C.success:C.textMuted,display:"flex",alignItems:"center",gap:3}}>
              {ok?<Check size={9}/>:<X size={9}/>}{l}
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

function Tabs({active,setActive}) {
  return (
    <div style={{display:"flex",background:C.elevated,borderRadius:12,padding:4,marginBottom:28,border:`1px solid ${C.border}`}}>
      {[["login","Ingresar"],["register","Registrar empresa"],["recover","Recuperar"]].map(([id,label])=>(
        <div key={id} onClick={()=>setActive(id)}
          style={{flex:1,padding:"8px 6px",borderRadius:9,cursor:"pointer",textAlign:"center",
            fontSize:12,fontWeight:active===id?700:400,
            background:active===id?C.primary+"22":"transparent",
            color:active===id?C.primary:C.textMuted,
            border:`1px solid ${active===id?C.primary+"40":"transparent"}`,
            transition:"all .2s",whiteSpace:"nowrap"}}>
          {label}
        </div>
      ))}
    </div>
  );
}

function LoginForm({onSuccess}) {
  const [email,setEmail]=useState("");
  const [pass,setPass]=useState("");
  const [showPass,setShowPass]=useState(false);
  const [remember,setRemember]=useState(false);
  const [loading,setLoading]=useState(false);
  const [errors,setErrors]=useState({});
  const [mfa,setMfa]=useState(false);

  const validate = () => {
    const e={};
    if(!email) e.email="Requerido";
    else if(!/\S+@\S+\.\S+/.test(email)) e.email="Email inválido";
    if(!pass) e.pass="Requerido";
    return e;
  };

  const handleLogin = () => {
    const e=validate();
    if(Object.keys(e).length){setErrors(e);return;}
    setLoading(true); setErrors({});
    setTimeout(()=>{
      setLoading(false);
      if(email==="admin@surveyai.cl"&&pass==="Admin123!") setMfa(true);
      else setErrors({general:"Credenciales incorrectas. Demo: admin@surveyai.cl / Admin123!"});
    },1400);
  };

  if(mfa) return (
    <div>
      <div style={{textAlign:"center",marginBottom:24}}>
        <div style={{width:56,height:56,borderRadius:16,background:`${C.primary}18`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px",border:`1px solid ${C.primary}30`}}>
          <Shield size={24} color={C.primary}/>
        </div>
        <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:4}}>Verificación en 2 pasos</div>
        <div style={{fontSize:13,color:C.textMuted}}>Código enviado a {email}</div>
      </div>
      <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:20}}>
        {[0,1,2,3,4,5].map(i=>(
          <input key={i} maxLength={1} style={{width:44,height:52,textAlign:"center",fontSize:22,fontWeight:800,background:C.elevated,border:`1.5px solid ${C.border}`,borderRadius:10,color:C.text,fontFamily:"inherit",outline:"none"}}
            onFocus={e=>e.currentTarget.style.borderColor=C.primary}
            onBlur={e=>e.currentTarget.style.borderColor=C.border}
            onChange={e=>{if(e.currentTarget.value&&e.currentTarget.nextElementSibling)e.currentTarget.nextElementSibling.focus();}}/>
        ))}
      </div>
      <button onClick={()=>onSuccess()} style={{width:"100%",padding:14,borderRadius:12,border:"none",background:C.gradPrimary,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
        Verificar e ingresar
      </button>
      <div style={{textAlign:"center",marginTop:14,fontSize:12,color:C.textMuted}}>
        ¿No llegó el código? <span style={{color:C.primary,cursor:"pointer",fontWeight:600}}>Reenviar</span>
      </div>
    </div>
  );

  return (
    <div>
      {errors.general && (
        <div style={{background:`${C.danger}14`,border:`1px solid ${C.danger}30`,borderRadius:10,padding:"10px 14px",marginBottom:18,display:"flex",alignItems:"center",gap:8,fontSize:13,color:C.danger}}>
          <AlertCircle size={14}/>{errors.general}
        </div>
      )}
      <Input label="Email corporativo" type="email" value={email} onChange={setEmail} placeholder="tu@empresa.cl" icon={Mail} error={errors.email}/>
      <Input label="Contraseña" type={showPass?"text":"password"} value={pass} onChange={setPass} placeholder="••••••••" icon={Lock} error={errors.pass}
        rightEl={<div onClick={()=>setShowPass(v=>!v)} style={{cursor:"pointer",color:C.textMuted}}>{showPass?<EyeOff size={15}/>:<Eye size={15}/>}</div>}/>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:22}}>
        <label style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer",fontSize:13,color:C.textSec}}>
          <div onClick={()=>setRemember(v=>!v)} style={{width:18,height:18,borderRadius:5,border:`1.5px solid ${remember?C.primary:C.border}`,background:remember?C.primary:"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all .2s"}}>
            {remember&&<Check size={11} color="#fff"/>}
          </div>
          Recordar sesión
        </label>
        <span style={{fontSize:13,color:C.primary,fontWeight:600,cursor:"pointer"}}>¿Olvidaste tu contraseña?</span>
      </div>
      <button onClick={handleLogin} disabled={loading}
        style={{width:"100%",padding:14,borderRadius:12,border:"none",background:loading?C.elevated:C.gradPrimary,color:loading?C.textMuted:"#fff",fontSize:15,fontWeight:700,cursor:loading?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:8,transition:"all .2s",boxShadow:loading?"none":`0 4px 20px ${C.primary}40`}}>
        {loading?<><RefreshCw size={15} style={{animation:"spin 1s linear infinite"}}/>Autenticando...</>:<>Ingresar al panel <ArrowRight size={15}/></>}
      </button>
      <div style={{display:"flex",gap:10,marginTop:14}}>
        {[["Google","G"],["Microsoft","M"]].map(([name,letter])=>(
          <button key={name} style={{flex:1,padding:"10px 14px",borderRadius:10,border:`1px solid ${C.border}`,background:C.elevated,color:C.textSec,fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
            <span style={{width:18,height:18,borderRadius:4,background:C.gradPrimary,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:900,color:"#fff"}}>{letter}</span>
            Continuar con {name}
          </button>
        ))}
      </div>
      <div style={{textAlign:"center",marginTop:16,padding:"10px 14px",background:`${C.primary}08`,borderRadius:10,border:`1px solid ${C.primary}18`}}>
        <div style={{fontSize:11,color:C.textMuted,marginBottom:2}}>Demo</div>
        <div style={{fontSize:11,color:C.textSec}}>Email: <code style={{color:C.primary}}>admin@surveyai.cl</code> · Pass: <code style={{color:C.primary}}>Admin123!</code></div>
      </div>
    </div>
  );
}

function RegisterForm({onSuccess}) {
  const [step,setStep]=useState(1);
  const [form,setForm]=useState({empresa:"",rut:"",giro:"",email:"",telefono:"",nombre:"",cargo:"",pass:"",passConf:"",terminos:false});
  const [showPass,setShowPass]=useState(false);
  const [loading,setLoading]=useState(false);
  const [errors,setErrors]=useState({});

  const set=(k,v)=>setForm(f=>({...f,[k]:v}));

  const validateStep1=()=>{
    const e={};
    if(!form.empresa) e.empresa="Requerido";
    if(!form.email) e.email="Requerido";
    else if(!/\S+@\S+\.\S+/.test(form.email)) e.email="Email inválido";
    if(!form.telefono) e.telefono="Requerido";
    return e;
  };

  const validateStep2=()=>{
    const e={};
    if(!form.nombre) e.nombre="Requerido";
    const {score}=checkStrength(form.pass);
    if(score<3) e.pass="Contraseña muy débil";
    if(form.pass!==form.passConf) e.passConf="Las contraseñas no coinciden";
    if(!form.terminos) e.terminos="Debes aceptar los términos";
    return e;
  };

  const handleNext=()=>{
    const e=validateStep1();
    if(Object.keys(e).length){setErrors(e);return;}
    setErrors({});setStep(2);
  };

  const handleRegister=()=>{
    const e=validateStep2();
    if(Object.keys(e).length){setErrors(e);return;}
    setLoading(true);
    setTimeout(()=>{setLoading(false);onSuccess();},1800);
  };

  const StepDots=()=>(
    <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,marginBottom:24}}>
      {[1,2].map(s=>(
        <div key={s} style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:28,height:28,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,background:s<=step?C.gradPrimary:C.elevated,color:s<=step?"#fff":C.textMuted,border:`1.5px solid ${s<=step?C.primary:C.border}`,transition:"all .3s"}}>
            {s<step?<Check size={13}/>:s}
          </div>
          <span style={{fontSize:11,color:s===step?C.primary:C.textMuted,fontWeight:s===step?700:400}}>
            {s===1?"Empresa":"Cuenta admin"}
          </span>
          {s<2&&<ChevronRight size={14} color={C.textMuted}/>}
        </div>
      ))}
    </div>
  );

  if(step===1) return (
    <div>
      <StepDots/>
      <Input label="Nombre de la empresa *" value={form.empresa} onChange={v=>set("empresa",v)} placeholder="Ej: Alimentos del Sur S.A." icon={Building2} error={errors.empresa}/>
      <Input label="RUT empresa" value={form.rut} onChange={v=>set("rut",v)} placeholder="76.543.210-K" icon={Info}/>
      <Input label="Giro comercial" value={form.giro} onChange={v=>set("giro",v)} placeholder="Estudio de mercado, retail..." icon={Globe}/>
      <Input label="Email corporativo *" type="email" value={form.email} onChange={v=>set("email",v)} placeholder="contacto@empresa.cl" icon={Mail} error={errors.email}/>
      <Input label="Teléfono *" value={form.telefono} onChange={v=>set("telefono",v)} placeholder="+56 9 XXXX XXXX" icon={Phone} error={errors.telefono}/>
      <button onClick={handleNext} style={{width:"100%",padding:14,borderRadius:12,border:"none",background:C.gradPrimary,color:"#fff",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:8,boxShadow:`0 4px 20px ${C.primary}40`}}>
        Siguiente <ArrowRight size={15}/>
      </button>
    </div>
  );

  return (
    <div>
      <StepDots/>
      <Input label="Nombre del administrador *" value={form.nombre} onChange={v=>set("nombre",v)} placeholder="Nombre completo" icon={User} error={errors.nombre}/>
      <Input label="Cargo" value={form.cargo} onChange={v=>set("cargo",v)} placeholder="Gerente, Jefe de proyectos..." icon={Building2}/>
      <Input label="Contraseña *" type={showPass?"text":"password"} value={form.pass} onChange={v=>set("pass",v)} placeholder="Mín. 8 caracteres" icon={Lock} error={errors.pass} hint="Usa mayúsculas, números y símbolos"
        rightEl={<div onClick={()=>setShowPass(v=>!v)} style={{cursor:"pointer",color:C.textMuted}}>{showPass?<EyeOff size={15}/>:<Eye size={15}/>}</div>}/>
      <StrengthBar password={form.pass}/>
      <Input label="Confirmar contraseña *" type="password" value={form.passConf} onChange={v=>set("passConf",v)} placeholder="Repite tu contraseña" icon={Lock} error={errors.passConf}/>
      <label style={{display:"flex",alignItems:"flex-start",gap:10,marginBottom:20,cursor:"pointer"}}>
        <div onClick={()=>set("terminos",!form.terminos)} style={{width:18,height:18,borderRadius:5,flexShrink:0,marginTop:1,border:`1.5px solid ${errors.terminos?C.danger:form.terminos?C.primary:C.border}`,background:form.terminos?C.primary:"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all .2s"}}>
          {form.terminos&&<Check size={11} color="#fff"/>}
        </div>
        <span style={{fontSize:12,color:C.textSec,lineHeight:1.5}}>
          Acepto los <span style={{color:C.primary,fontWeight:600}}>Términos de servicio</span> y la <span style={{color:C.primary,fontWeight:600}}>Política de privacidad</span>
        </span>
      </label>
      {errors.terminos&&<div style={{fontSize:11,color:C.danger,marginTop:-14,marginBottom:14,display:"flex",alignItems:"center",gap:4}}><AlertCircle size={11}/>{errors.terminos}</div>}
      <div style={{display:"flex",gap:10}}>
        <button onClick={()=>setStep(1)} style={{flex:1,padding:13,borderRadius:12,border:`1px solid ${C.border}`,background:C.elevated,color:C.textSec,fontSize:14,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Anterior</button>
        <button onClick={handleRegister} disabled={loading} style={{flex:2,padding:13,borderRadius:12,border:"none",background:loading?C.elevated:C.gradPrimary,color:loading?C.textMuted:"#fff",fontSize:14,fontWeight:700,cursor:loading?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
          {loading?<><RefreshCw size={14} style={{animation:"spin 1s linear infinite"}}/>Creando cuenta...</>:<>Crear cuenta <ArrowRight size={14}/></>}
        </button>
      </div>
    </div>
  );
}

function RecoverForm() {
  const [email,setEmail]=useState("");
  const [sent,setSent]=useState(false);
  const [loading,setLoading]=useState(false);

  if(sent) return (
    <div style={{textAlign:"center",padding:"20px 0"}}>
      <div style={{width:64,height:64,borderRadius:18,background:`${C.success}18`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px",border:`1px solid ${C.success}30`}}>
        <CheckCircle size={28} color={C.success}/>
      </div>
      <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:8}}>Revisa tu correo</div>
      <div style={{fontSize:13,color:C.textSec,lineHeight:1.6,marginBottom:20}}>
        Enviamos un enlace a<br/><strong style={{color:C.primary}}>{email}</strong>
      </div>
      <div style={{fontSize:12,color:C.textMuted}}>Expira en 30 min · <span style={{color:C.primary,cursor:"pointer"}}>Reenviar</span></div>
    </div>
  );

  return (
    <div>
      <div style={{textAlign:"center",marginBottom:20,fontSize:13,color:C.textSec,lineHeight:1.6}}>
        Ingresa tu email y te enviaremos un enlace seguro para restablecer tu contraseña.
      </div>
      <Input label="Email corporativo" type="email" value={email} onChange={setEmail} placeholder="tu@empresa.cl" icon={Mail}/>
      <button onClick={()=>{if(!email)return;setLoading(true);setTimeout(()=>{setLoading(false);setSent(true);},1400);}} disabled={loading||!email}
        style={{width:"100%",padding:14,borderRadius:12,border:"none",background:(!email||loading)?C.elevated:C.gradPrimary,color:(!email||loading)?C.textMuted:"#fff",fontSize:15,fontWeight:700,cursor:(!email||loading)?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:8,transition:"all .2s"}}>
        {loading?<><RefreshCw size={15} style={{animation:"spin 1s linear infinite"}}/>Enviando...</>:<>Enviar enlace <ArrowRight size={15}/></>}
      </button>
    </div>
  );
}

function SuccessScreen() {
  return (
    <div style={{textAlign:"center",padding:"20px 0"}}>
      <div style={{width:72,height:72,borderRadius:20,background:`${C.success}18`,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px",border:`1px solid ${C.success}30`}}>
        <CheckCircle size={32} color={C.success}/>
      </div>
      <div style={{fontSize:22,fontWeight:900,color:C.text,marginBottom:8}}>¡Bienvenido!</div>
      <div style={{fontSize:14,color:C.textSec,marginBottom:24}}>Acceso verificado. Redirigiendo al panel...</div>
      <div style={{display:"flex",gap:5,justifyContent:"center"}}>
        {[0,1,2].map(i=><div key={i} style={{width:8,height:8,borderRadius:"50%",background:C.primary,animation:`pulse 1.2s ease-in-out ${i*0.2}s infinite`}}/>)}
      </div>
    </div>
  );
}

export default function LoginSurveyAI() {
  const [tab,setTab]=useState("login");
  const [success,setSuccess]=useState(false);

  return (
    <div style={{minHeight:"100vh",background:`linear-gradient(135deg,#070E1C 0%,#0B1527 50%,#070E1C 100%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:24,fontFamily:"'Inter',-apple-system,BlinkMacSystemFont,sans-serif"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        input,button{font-family:inherit}
        @keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}
        @keyframes pulse{0%,100%{opacity:.4;transform:scale(.8)}50%{opacity:1;transform:scale(1)}}
        @keyframes fadeIn{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
      `}</style>

      <div style={{position:"fixed",inset:0,overflow:"hidden",pointerEvents:"none",zIndex:0}}>
        {[0,1,2,3].map(i=>(
          <div key={i} style={{position:"absolute",borderRadius:"50%",background:i%2===0?"rgba(6,182,212,0.06)":"rgba(139,92,246,0.05)",width:[300,200,400,250][i],height:[300,200,400,250][i],left:["-10%","60%","30%","80%"][i],top:["-10%","70%","-20%","10%"][i],filter:"blur(60px)"}}/>
        ))}
      </div>

      <div style={{width:"100%",maxWidth:480,position:"relative",zIndex:1,animation:"fadeIn .5s ease-out"}}>
        <div style={{textAlign:"center",marginBottom:24}}>
          <img src={LOGO_SRC} alt="SurveyAI" style={{width:150,height:150,objectFit:"contain",filter:"drop-shadow(0 0 24px rgba(6,182,212,0.3))"}}/>
          <div style={{fontSize:11,color:"#3D5070",letterSpacing:".1em",marginTop:-6}}>ENCUESTA · ANALIZA · CREA EL FUTURO</div>
        </div>

        <div style={{background:"#0F1D35",borderRadius:24,padding:32,border:"1px solid rgba(6,182,212,0.12)",boxShadow:"0 24px 60px rgba(0,0,0,.5)"}}>
          {success ? <SuccessScreen/> : (
            <>
              <Tabs active={tab} setActive={setTab}/>
              {tab==="login"&&<LoginForm onSuccess={()=>setSuccess(true)}/>}
              {tab==="register"&&<RegisterForm onSuccess={()=>setSuccess(true)}/>}
              {tab==="recover"&&<RecoverForm/>}
            </>
          )}
        </div>

        <div style={{display:"flex",justifyContent:"center",gap:24,marginTop:18}}>
          {["JWT seguro","2FA activado","256-bit SSL"].map(label=>(
            <div key={label} style={{display:"flex",alignItems:"center",gap:5,fontSize:10,color:"#3D5070"}}>
              <Shield size={10} color="#06B6D4"/>{label}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
